package com.enterprise.samlsp.service;

import com.enterprise.samlsp.config.SamlConfig;
import com.enterprise.samlsp.model.SamlUserAttributes;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.w3c.dom.*;
import org.xml.sax.InputSource;

import javax.xml.XMLConstants;
import javax.xml.crypto.*;
import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.KeyInfo;
import javax.xml.crypto.dsig.keyinfo.X509Data;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.io.StringReader;
import java.nio.charset.StandardCharsets;
import java.security.Key;
import java.security.PublicKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.time.Instant;
import java.time.format.DateTimeFormatter;
import java.util.*;

@Service
public class SamlResponseParser {

    private static final Logger logger = LoggerFactory.getLogger(SamlResponseParser.class);

    private static final String SAML2_PROTOCOL_NS = "urn:oasis:names:tc:SAML:2.0:protocol";
    private static final String SAML2_ASSERTION_NS = "urn:oasis:names:tc:SAML:2.0:assertion";
    private static final String XMLDSIG_NS = "http://www.w3.org/2000/09/xmldsig#";

    private final SamlConfig samlConfig;

    public SamlResponseParser(SamlConfig samlConfig) {
        this.samlConfig = samlConfig;
    }

    public SamlUserAttributes parseSamlResponse(String samlResponseBase64) throws SamlProcessingException {
        try {
            byte[] decodedBytes = Base64.getDecoder().decode(samlResponseBase64);
            String samlResponseXml = new String(decodedBytes, StandardCharsets.UTF_8);

            logger.debug("Decoded SAML Response XML: {}", samlResponseXml);

            Document document = parseXmlDocument(samlResponseXml);

            validateResponseStatus(document);
            validateIssuer(document);
            validateDestination(document);

            if (samlConfig.isWantAssertionsSigned()) {
                validateSignature(document);
            }

            Element assertion = extractAssertion(document);
            if (assertion == null) {
                throw new SamlProcessingException("No assertion found in SAML response");
            }

            validateConditions(assertion);
            validateSubjectConfirmation(assertion);

            return extractUserAttributes(assertion, document);

        } catch (SamlProcessingException e) {
            throw e;
        } catch (Exception e) {
            logger.error("Error processing SAML response", e);
            throw new SamlProcessingException("Failed to process SAML response: " + e.getMessage(), e);
        }
    }

    private Document parseXmlDocument(String xml) throws SamlProcessingException {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);

            // Prevent XXE attacks
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            DocumentBuilder builder = factory.newDocumentBuilder();
            InputSource inputSource = new InputSource(new StringReader(xml));
            return builder.parse(inputSource);
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to parse SAML XML document", e);
        }
    }

    private void validateResponseStatus(Document document) throws SamlProcessingException {
        NodeList statusCodeNodes = document.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusCode");
        if (statusCodeNodes.getLength() == 0) {
            throw new SamlProcessingException("No StatusCode element found in SAML response");
        }

        Element statusCode = (Element) statusCodeNodes.item(0);
        String statusValue = statusCode.getAttribute("Value");

        if (!"urn:oasis:names:tc:SAML:2.0:status:Success".equals(statusValue)) {
            // Check for status message
            NodeList statusMessageNodes = document.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusMessage");
            String message = "";
            if (statusMessageNodes.getLength() > 0) {
                message = statusMessageNodes.item(0).getTextContent();
            }
            throw new SamlProcessingException("SAML authentication failed. Status: " + statusValue +
                    (message.isEmpty() ? "" : ", Message: " + message));
        }

        logger.debug("SAML response status: Success");
    }

    private void validateIssuer(Document document) throws SamlProcessingException {
        NodeList issuerNodes = document.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (issuerNodes.getLength() == 0) {
            throw new SamlProcessingException("No Issuer element found in SAML response");
        }

        // The first Issuer should be the response-level issuer
        String issuer = issuerNodes.item(0).getTextContent().trim();

        if (samlConfig.getIdpEntityId() != null && !samlConfig.getIdpEntityId().isEmpty()) {
            if (!samlConfig.getIdpEntityId().equals(issuer)) {
                throw new SamlProcessingException("SAML response issuer mismatch. Expected: " +
                        samlConfig.getIdpEntityId() + ", Got: " + issuer);
            }
        }

        logger.debug("SAML response issuer validated: {}", issuer);
    }

    private void validateDestination(Document document) throws SamlProcessingException {
        Element responseElement = document.getDocumentElement();
        String destination = responseElement.getAttribute("Destination");

        if (destination != null && !destination.isEmpty()) {
            if (samlConfig.getAcsUrl() != null && !samlConfig.getAcsUrl().isEmpty()) {
                if (!samlConfig.getAcsUrl().equals(destination)) {
                    throw new SamlProcessingException("SAML response destination mismatch. Expected: " +
                            samlConfig.getAcsUrl() + ", Got: " + destination);
                }
            }
        }

        logger.debug("SAML response destination validated");
    }

    private void validateSignature(Document document) throws SamlProcessingException {
        try {
            NodeList signatureNodes = document.getElementsByTagNameNS(XMLDSIG_NS, "Signature");
            if (signatureNodes.getLength() == 0) {
                throw new SamlProcessingException("No XML signature found in SAML response");
            }

            X509Certificate idpCertificate = loadIdpCertificate();

            for (int i = 0; i < signatureNodes.getLength(); i++) {
                Element signatureElement = (Element) signatureNodes.item(i);

                DOMValidateContext validateContext = new DOMValidateContext(
                        new SimpleKeySelector(idpCertificate.getPublicKey()), signatureElement);

                // Set ID attribute awareness
                setIdAttributes(document, validateContext);

                XMLSignatureFactory signatureFactory = XMLSignatureFactory.getInstance("DOM");
                XMLSignature signature = signatureFactory.unmarshalXMLSignature(validateContext);

                boolean valid = signature.validate(validateContext);

                if (!valid) {
                    // Log detailed validation info
                    boolean signatureValueValid = signature.getSignatureValue().validate(validateContext);
                    logger.error("Signature value validation: {}", signatureValueValid);

                    for (Object ref : signature.getSignedInfo().getReferences()) {
                        Reference reference = (Reference) ref;
                        boolean refValid = reference.validate(validateContext);
                        logger.error("Reference [{}] validation: {}", reference.getURI(), refValid);
                    }

                    throw new SamlProcessingException("XML signature validation failed");
                }
            }

            logger.debug("SAML response signature validated successfully");

        } catch (SamlProcessingException e) {
            throw e;
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to validate XML signature", e);
        }
    }

    private void setIdAttributes(Document document, DOMValidateContext validateContext) {
        // Set ID attributes on Response element
        Element responseElement = document.getDocumentElement();
        if (responseElement.hasAttribute("ID")) {
            validateContext.setIdAttributeNS(responseElement, null, "ID");
        }

        // Set ID attributes on Assertion elements
        NodeList assertions = document.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");
        for (int i = 0; i < assertions.getLength(); i++) {
            Element assertion = (Element) assertions.item(i);
            if (assertion.hasAttribute("ID")) {
                validateContext.setIdAttributeNS(assertion, null, "ID");
            }
        }
    }

    private X509Certificate loadIdpCertificate() throws SamlProcessingException {
        try {
            String certPem = samlConfig.getIdpCertificate();
            if (certPem == null || certPem.isEmpty()) {
                throw new SamlProcessingException("IdP certificate not configured");
            }

            certPem = certPem.replace("-----BEGIN CERTIFICATE-----", "")
                    .replace("-----END CERTIFICATE-----", "")
                    .replaceAll("\\s+", "");

            byte[] certBytes = Base64.getDecoder().decode(certPem);
            CertificateFactory certFactory = CertificateFactory.getInstance("X.509");
            return (X509Certificate) certFactory.generateCertificate(new ByteArrayInputStream(certBytes));

        } catch (SamlProcessingException e) {
            throw e;
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to load IdP certificate", e);
        }
    }

    private Element extractAssertion(Document document) {
        NodeList assertions = document.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");
        if (assertions.getLength() > 0) {
            return (Element) assertions.item(0);
        }
        return null;
    }

    private void validateConditions(Element assertion) throws SamlProcessingException {
        NodeList conditionsNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Conditions");
        if (conditionsNodes.getLength() == 0) {
            logger.warn("No Conditions element found in assertion");
            return;
        }

        Element conditions = (Element) conditionsNodes.item(0);

        String notBefore = conditions.getAttribute("NotBefore");
        String notOnOrAfter = conditions.getAttribute("NotOnOrAfter");

        Instant now = Instant.now();
        int skewSeconds = samlConfig.getResponseSkew();

        if (notBefore != null && !notBefore.isEmpty()) {
            Instant notBeforeInstant = Instant.parse(notBefore);
            if (now.plusSeconds(skewSeconds).isBefore(notBeforeInstant)) {
                throw new SamlProcessingException("SAML assertion is not yet valid. NotBefore: " + notBefore);
            }
        }

        if (notOnOrAfter != null && !notOnOrAfter.isEmpty()) {
            Instant notOnOrAfterInstant = Instant.parse(notOnOrAfter);
            if (now.minusSeconds(skewSeconds).isAfter(notOnOrAfterInstant) || now.minusSeconds(skewSeconds).equals(notOnOrAfterInstant)) {
                throw new SamlProcessingException("SAML assertion has expired. NotOnOrAfter: " + notOnOrAfter);
            }
        }

        // Validate AudienceRestriction
        NodeList audienceRestrictions = conditions.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AudienceRestriction");
        if (audienceRestrictions.getLength() > 0 && samlConfig.getEntityId() != null) {
            Element audienceRestriction = (Element) audienceRestrictions.item(0);
            NodeList audiences = audienceRestriction.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Audience");

            boolean audienceMatched = false;
            for (int i = 0; i < audiences.getLength(); i++) {
                String audience = audiences.item(i).getTextContent().trim();
                if (samlConfig.getEntityId().equals(audience)) {
                    audienceMatched = true;
                    break;
                }
            }

            if (!audienceMatched) {
                throw new SamlProcessingException("SAML assertion audience does not match SP entity ID: " +
                        samlConfig.getEntityId());
            }
        }

        logger.debug("SAML assertion conditions validated");
    }

    private void validateSubjectConfirmation(Element assertion) throws SamlProcessingException {
        NodeList subjectConfirmations = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "SubjectConfirmation");

        for (int i = 0; i < subjectConfirmations.getLength(); i++) {
            Element subjectConfirmation = (Element) subjectConfirmations.item(i);
            String method = subjectConfirmation.getAttribute("Method");

            if ("urn:oasis:names:tc:SAML:2.0:cm:bearer".equals(method)) {
                NodeList confirmationData = subjectConfirmation.getElementsByTagNameNS(
                        SAML2_ASSERTION_NS, "SubjectConfirmationData");

                if (confirmationData.getLength() > 0) {
                    Element data = (Element) confirmationData.item(0);

                    // Validate NotOnOrAfter
                    String notOnOrAfter = data.getAttribute("NotOnOrAfter");
                    if (notOnOrAfter != null && !notOnOrAfter.isEmpty()) {
                        Instant notOnOrAfterInstant = Instant.parse(notOnOrAfter);
                        Instant now = Instant.now();
                        int skew = samlConfig.getResponseSkew();

                        if (now.minusSeconds(skew).isAfter(notOnOrAfterInstant)) {
                            throw new SamlProcessingException("Subject confirmation has expired");
                        }
                    }

                    // Validate Recipient
                    String recipient = data.getAttribute("Recipient");
                    if (recipient != null && !recipient.isEmpty() && samlConfig.getAcsUrl() != null) {
                        if (!samlConfig.getAcsUrl().equals(recipient)) {
                            throw new SamlProcessingException("Subject confirmation recipient mismatch");
                        }
                    }
                }

                logger.debug("Subject confirmation validated (bearer)");
                return;
            }
        }

        logger.warn("No bearer SubjectConfirmation found");
    }

    private SamlUserAttributes extractUserAttributes(Element assertion, Document document) throws SamlProcessingException {
        SamlUserAttributes userAttributes = new SamlUserAttributes();

        // Extract Issuer
        NodeList issuerNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (issuerNodes.getLength() > 0) {
            userAttributes.setIssuer(issuerNodes.item(0).getTextContent().trim());
        }

        // Extract NameID
        NodeList nameIdNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "NameID");
        if (nameIdNodes.getLength() > 0) {
            Element nameIdElement = (Element) nameIdNodes.item(0);
            userAttributes.setNameId(nameIdElement.getTextContent().trim());
            String format = nameIdElement.getAttribute("Format");
            if (format != null && !format.isEmpty()) {
                userAttributes.setNameIdFormat(format);
            }
        }

        // Extract AuthnStatement
        NodeList authnStatements = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AuthnStatement");
        if (authnStatements.getLength() > 0) {
            Element authnStatement = (Element) authnStatements.item(0);

            String sessionIndex = authnStatement.getAttribute("SessionIndex");
            if (sessionIndex != null && !sessionIndex.isEmpty()) {
                userAttributes.setSessionIndex(sessionIndex);
            }

            String authnInstant = authnStatement.getAttribute("AuthnInstant");
            if (authnInstant != null && !authnInstant.isEmpty()) {
                userAttributes.setAuthenticationInstant(authnInstant);

                // Validate authentication age
                try {
                    Instant authInstant = Instant.parse(authnInstant);
                    Instant maxAge = Instant.now().minusSeconds(samlConfig.getMaxAuthenticationAge());
                    if (authInstant.isBefore(maxAge)) {
                        logger.warn("Authentication instant exceeds max age: {}", authnInstant);
                    }
                } catch (Exception e) {
                    logger.warn("Could not parse AuthnInstant: {}", authnInstant);
                }
            }

            // Extract AuthnContext
            NodeList authnContextClassRef = authnStatement.getElementsByTagNameNS(
                    SAML2_ASSERTION_NS, "AuthnContextClassRef");
            if (authnContextClassRef.getLength() > 0) {
                userAttributes.setAuthenticationMethod(authnContextClassRef.item(0).getTextContent().trim());
            }
        }

        // Extract Attributes from AttributeStatement
        NodeList attributeStatements = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeStatement");
        Map<String, List<String>> attributes = new HashMap<>();

        for (int i = 0; i < attributeStatements.getLength(); i++) {
            Element attributeStatement = (Element) attributeStatements.item(i);
            NodeList attributeNodes = attributeStatement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Attribute");

            for (int j = 0; j < attributeNodes.getLength(); j++) {
                Element attribute = (Element) attributeNodes.item(j);
                String name = attribute.getAttribute("Name");
                String friendlyName = attribute.getAttribute("FriendlyName");

                List<String> values = new ArrayList<>();
                NodeList attributeValues = attribute.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeValue");

                for (int k = 0; k < attributeValues.getLength(); k++) {
                    String value = attributeValues.item(k).getTextContent().trim();
                    if (!value.isEmpty()) {
                        values.add(value);
                    }
                }

                if (name != null && !name.isEmpty()) {
                    attributes.put(name, values);
                }

                // Also store by friendly name if available
                if (friendlyName != null && !friendlyName.isEmpty() && !friendlyName.equals(name)) {
                    attributes.put(friendlyName, values);
                }
            }
        }

        userAttributes.setAttributes(attributes);

        logger.info("Extracted SAML user attributes - NameID: {}, Attributes count: {}",
                userAttributes.getNameId(), attributes.size());

        return userAttributes;
    }

    // Simple key selector for XML signature validation
    private static class SimpleKeySelector extends KeySelector {
        private final PublicKey publicKey;

        public SimpleKeySelector(PublicKey publicKey) {
            this.publicKey = publicKey;
        }

        @Override
        public KeySelectorResult select(KeyInfo keyInfo, Purpose purpose,
                                         AlgorithmMethod method, XMLCryptoContext context) {
            return () -> publicKey;
        }
    }
}

