package com.enterprise.samlsp.service;

import com.enterprise.samlsp.model.SamlUserAttributes;
import com.enterprise.samlsp.security.SamlAuthenticationToken;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Service;

import javax.servlet.http.HttpSession;
import java.util.List;
import java.util.Map;

@Service
public class SamlSessionService {

    private static final Logger logger = LoggerFactory.getLogger(SamlSessionService.class);

    public static final String SESSION_ATTR_SAML_USER = "SAML_USER_ATTRIBUTES";
    public static final String SESSION_ATTR_NAME_ID = "SAML_NAME_ID";
    public static final String SESSION_ATTR_SESSION_INDEX = "SAML_SESSION_INDEX";
    public static final String SESSION_ATTR_EMAIL = "SAML_USER_EMAIL";
    public static final String SESSION_ATTR_DISPLAY_NAME = "SAML_USER_DISPLAY_NAME";
    public static final String SESSION_ATTR_FIRST_NAME = "SAML_USER_FIRST_NAME";
    public static final String SESSION_ATTR_LAST_NAME = "SAML_USER_LAST_NAME";
    public static final String SESSION_ATTR_ROLES = "SAML_USER_ROLES";

    public void createAuthenticatedSession(HttpSession session, SamlUserAttributes userAttributes) {
        // Store complete user attributes object
        session.setAttribute(SESSION_ATTR_SAML_USER, userAttributes);

        // Store common attributes individually for easy access
        session.setAttribute(SESSION_ATTR_NAME_ID, userAttributes.getNameId());

        if (userAttributes.getSessionIndex() != null) {
            session.setAttribute(SESSION_ATTR_SESSION_INDEX, userAttributes.getSessionIndex());
        }

        if (userAttributes.getEmail() != null) {
            session.setAttribute(SESSION_ATTR_EMAIL, userAttributes.getEmail());
        }

        if (userAttributes.getDisplayName() != null) {
            session.setAttribute(SESSION_ATTR_DISPLAY_NAME, userAttributes.getDisplayName());
        }

        if (userAttributes.getFirstName() != null) {
            session.setAttribute(SESSION_ATTR_FIRST_NAME, userAttributes.getFirstName());
        }

        if (userAttributes.getLastName() != null) {
            session.setAttribute(SESSION_ATTR_LAST_NAME, userAttributes.getLastName());
        }

        if (userAttributes.getRoles() != null) {
            session.setAttribute(SESSION_ATTR_ROLES, userAttributes.getRoles());
        }

        // Store all SAML attributes with a prefix
        for (Map.Entry<String, List<String>> entry : userAttributes.getAttributes().entrySet()) {
            String key = "SAML_ATTR_" + sanitizeAttributeName(entry.getKey());
            if (entry.getValue().size() == 1) {
                session.setAttribute(key, entry.getValue().get(0));
            } else {
                session.setAttribute(key, entry.getValue());
            }
        }

        // Set Spring Security authentication context
        SamlAuthenticationToken authToken = new SamlAuthenticationToken(userAttributes);
        SecurityContextHolder.getContext().setAuthentication(authToken);

        logger.info("Created authenticated session for user: {}, session ID: {}",
                userAttributes.getNameId(), session.getId());
    }

    public void invalidateSession(HttpSession session) {
        if (session != null) {
            String nameId = (String) session.getAttribute(SESSION_ATTR_NAME_ID);
            logger.info("Invalidating session for user: {}", nameId);
            session.invalidate();
            SecurityContextHolder.clearContext();
        }
    }

    public SamlUserAttributes getUserAttributes(HttpSession session) {
        return (SamlUserAttributes) session.getAttribute(SESSION_ATTR_SAML_USER);
    }

    public boolean isAuthenticated(HttpSession session) {
        return session.getAttribute(SESSION_ATTR_SAML_USER) != null;
    }

    private String sanitizeAttributeName(String name) {
        return name.replaceAll("[^a-zA-Z0-9_]", "_");
    }
}

