// SamlAuthnRequestService.java
// ============================================================
package com.enterprise.samlsp.service;

import com.enterprise.samlsp.config.SamlConfig;
import org.springframework.stereotype.Service;

import java.io.ByteArrayOutputStream;
import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.Base64;
import java.util.UUID;
import java.util.zip.Deflater;
import java.util.zip.DeflaterOutputStream;

@Service
public class SamlAuthnRequestService {

    private final SamlConfig samlConfig;

    public SamlAuthnRequestService(SamlConfig samlConfig) {
        this.samlConfig = samlConfig;
    }

    public String generateAuthnRequest() throws Exception {
        String id = "_" + UUID.randomUUID().toString();
        String issueInstant = Instant.now().toString();

        String authnRequest = "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
                "<samlp:AuthnRequest " +
                "xmlns:samlp=\"urn:oasis:names:tc:SAML:2.0:protocol\" " +
                "xmlns:saml=\"urn:oasis:names:tc:SAML:2.0:assertion\" " +
                "ID=\"" + id + "\" " +
                "Version=\"2.0\" " +
                "IssueInstant=\"" + issueInstant + "\" " +
                "Destination=\"" + samlConfig.getIdpSsoUrl() + "\" " +
                "AssertionConsumerServiceURL=\"" + samlConfig.getAcsUrl() + "\" " +
                "ProtocolBinding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\">" +
                "<saml:Issuer>" + samlConfig.getEntityId() + "</saml:Issuer>" +
                "<samlp:NameIDPolicy Format=\"urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress\" " +
                "AllowCreate=\"true\"/>" +
                "</samlp:AuthnRequest>";

        // Deflate and Base64 encode for HTTP-Redirect binding
        ByteArrayOutputStream byteArrayOutputStream = new ByteArrayOutputStream();
        Deflater deflater = new Deflater(Deflater.DEFLATED, true);
        DeflaterOutputStream deflaterOutputStream = new DeflaterOutputStream(byteArrayOutputStream, deflater);
        deflaterOutputStream.write(authnRequest.getBytes(StandardCharsets.UTF_8));
        deflaterOutputStream.close();

        return Base64.getEncoder().encodeToString(byteArrayOutputStream.toByteArray());
    }

    public String buildRedirectUrl() throws Exception {
        String encodedRequest = generateAuthnRequest();
        String encodedRequestParam = java.net.URLEncoder.encode(encodedRequest, StandardCharsets.UTF_8.name());
        return samlConfig.getIdpSsoUrl() + "?SAMLRequest=" + encodedRequestParam;
    }
}

