// ============================================================
package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.config.SamlConfig;
import com.enterprise.samlsp.model.SamlUserAttributes;
import com.enterprise.samlsp.service.SamlAuthnRequestService;
import com.enterprise.samlsp.service.SamlProcessingException;
import com.enterprise.samlsp.service.SamlResponseParser;
import com.enterprise.samlsp.service.SamlSessionService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.servlet.view.RedirectView;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpSession;

@Controller
public class SamlController {

    private static final Logger logger = LoggerFactory.getLogger(SamlController.class);

    private final SamlResponseParser samlResponseParser;
    private final SamlSessionService samlSessionService;
    private final SamlAuthnRequestService samlAuthnRequestService;
    private final SamlConfig samlConfig;

    public SamlController(SamlResponseParser samlResponseParser,
                          SamlSessionService samlSessionService,
                          SamlAuthnRequestService samlAuthnRequestService,
                          SamlConfig samlConfig) {
        this.samlResponseParser = samlResponseParser;
        this.samlSessionService = samlSessionService;
        this.samlAuthnRequestService = samlAuthnRequestService;
        this.samlConfig = samlConfig;
    }

    @GetMapping("/login")
    public String loginPage(Model model) {
        model.addAttribute("idpSsoUrl", samlConfig.getIdpSsoUrl());
        return "login";
    }

    @GetMapping("/saml/login")
    public RedirectView initiateSamlLogin() {
        try {
            String redirectUrl = samlAuthnRequestService.buildRedirectUrl();
            logger.info("Initiating SAML login, redirecting to IdP: {}", samlConfig.getIdpSsoUrl());
            return new RedirectView(redirectUrl);
        } catch (Exception e) {
            logger.error("Failed to initiate SAML login", e);
            return new RedirectView("/login?error=saml_init_failed");
        }
    }

    @PostMapping("/saml/acs")
    public String assertionConsumerService(
            @RequestParam("SAMLResponse") String samlResponse,
            @RequestParam(value = "RelayState", required = false) String relayState,
            HttpServletRequest request,
            HttpSession session,
            Model model) {

        logger.info("Received SAML response at ACS endpoint from IP: {}", request.getRemoteAddr());

        try {
            // Invalidate any existing session to prevent session fixation
            if (samlSessionService.isAuthenticated(session)) {
                session.invalidate();
                session = request.getSession(true);
            }

            // Parse and validate the SAML response
            SamlUserAttributes userAttributes = samlResponseParser.parseSamlResponse(samlResponse);

            // Create authenticated session with user attributes
            samlSessionService.createAuthenticatedSession(session, userAttributes);

            logger.info("Successfully authenticated user: {} via SAML", userAttributes.getNameId());

            // Redirect to relay state or default dashboard
            if (relayState != null && !relayState.isEmpty() && isValidRelayState(relayState)) {
                return "redirect:" + relayState;
            }

            return "redirect:/dashboard";

        } catch (SamlProcessingException e) {
            logger.error("SAML processing error: {}", e.getMessage());
            model.addAttribute("error", "Authentication failed: " + e.getMessage());
            return "login";
        } catch (Exception e) {
            logger.error("Unexpected error processing SAML response", e);
            model.addAttribute("error", "An unexpected error occurred during authentication");
            return "login";
        }
    }

    @GetMapping("/saml/slo")
    public String singleLogout(HttpSession session) {
        logger.info("Processing single logout");
        samlSessionService.invalidateSession(session);
        return "redirect:/login?logout=true";
    }

    @PostMapping("/saml/slo")
    public String singleLogoutPost(
            @RequestParam(value = "SAMLRequest", required = false) String samlRequest,
            @RequestParam(value = "SAMLResponse", required = false) String samlResponse,
            HttpSession session) {

        logger.info("Processing single logout (POST)");
        samlSessionService.invalidateSession(session);
        return "redirect:/login?logout=true";
    }

    @GetMapping("/saml/metadata")
    @ResponseBody
    public String spMetadata() {
        return generateSpMetadata();
    }

    @GetMapping("/dashboard")
    public String dashboard(HttpSession session, Model model) {
        SamlUserAttributes userAttributes = samlSessionService.getUserAttributes(session);
        if (userAttributes == null) {
            return "redirect:/saml/login";
        }

        model.addAttribute("user", userAttributes);
        model.addAttribute("nameId", userAttributes.getNameId());
        model.addAttribute("email", userAttributes.getEmail());
        model.addAttribute("displayName", userAttributes.getDisplayName());
        model.addAttribute("firstName", userAttributes.getFirstName());
        model.addAttribute("lastName", userAttributes.getLastName());
        model.addAttribute("roles", userAttributes.getRoles());
        model.addAttribute("allAttributes", userAttributes.getAttributes());
        model.addAttribute("authMethod", userAttributes.getAuthenticationMethod());
        model.addAttribute("issuer", userAttributes.getIssuer());

        return "dashboard";
    }

    private boolean isValidRelayState(String relayState) {
        // Prevent open redirect attacks
        return relayState.startsWith("/") && !relayState.startsWith("//");
    }

    private String generateSpMetadata() {
        return "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
                "<md:EntityDescriptor " +
                "xmlns:md=\"urn:oasis:names:tc:SAML:2.0:metadata\" " +
                "entityID=\"" + samlConfig.getEntityId() + "\">" +
                "<md:SPSSODescriptor " +
                "AuthnRequestsSigned=\"false\" " +
                "WantAssertionsSigned=\"" + samlConfig.isWantAssertionsSigned() + "\" " +
                "protocolSupportEnumeration=\"urn:oasis:names:tc:SAML:2.0:protocol\">" +
                "<md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>" +
                "<md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:persistent</md:NameIDFormat>" +
                "<md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:transient</md:NameIDFormat>" +
                "<md:AssertionConsumerService " +
                "Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\" " +
                "Location=\"" + samlConfig.getAcsUrl() + "\" " +
                "index=\"0\" " +
                "isDefault=\"true\"/>" +
                "<md:SingleLogoutService " +
                "Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect\" " +
                "Location=\"" + samlConfig.getAcsUrl().replace("/saml/acs", "/saml/slo") + "\"/>" +
                "</md:SPSSODescriptor>" +
                "</md:EntityDescriptor>";
    }
}

// ============================================================
// SamlApiController.java - REST API for checking auth status
// ============================================================
package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.model.SamlUserAttributes;
import com.enterprise.samlsp.service.SamlSessionService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import javax.servlet.http.HttpSession;
import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class SamlApiController {

    private final SamlSessionService samlSessionService;

    public SamlApiController(SamlSessionService samlSessionService) {
        this.samlSessionService = samlSessionService;
    }

    @GetMapping("/user")
    public ResponseEntity<Map<String, Object>> getCurrentUser(HttpSession session) {
        SamlUserAttributes userAttributes = samlSessionService.getUserAttributes(session);

        if (userAttributes == null) {
            return ResponseEntity.status(401).build();
        }

        Map<String, Object> userInfo = new HashMap<>();
        userInfo.put("nameId", userAttributes.getNameId());
        userInfo.put("email", userAttributes.getEmail());
        userInfo.put("displayName", userAttributes.getDisplayName());
        userInfo.put("firstName", userAttributes.getFirstName());
        userInfo.put("lastName", userAttributes.getLastName());
        userInfo.put("roles", userAttributes.getRoles());
        userInfo.put("issuer", userAttributes.getIssuer());
        userInfo.put("authenticationMethod", userAttributes.getAuthenticationMethod());
        userInfo.put("attributes", userAttributes.getAttributes());

        return ResponseEntity.ok(userInfo);
    }

    @GetMapping("/auth/status")
    public ResponseEntity<Map<String, Object>> authStatus(HttpSession session) {
        Map<String, Object> status = new HashMap<>();
        boolean authenticated = samlSessionService.isAuthenticated(session);
        status.put("authenticated", authenticated);

        if (authenticated) {
            SamlUserAttributes attrs = samlSessionService.getUserAttributes(session);
            status.put("nameId", attrs.getNameId());
            status.put("sessionIndex", attrs.getSessionIndex());
        }

        return ResponseEntity.ok(status);
    }
}

