// ReplayAttackPrevention.java
// ============================================================
package com.enterprise.samlsp.service;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;

import java.time.Instant;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Component
public class ReplayAttackPrevention {

    private static final Logger logger = LoggerFactory.getLogger(ReplayAttackPrevention.class);

    // Store response IDs with their expiration times
    private final Map<String, Instant> processedResponseIds = new ConcurrentHashMap<>();

    // Default expiration: 10 minutes
    private static final long EXPIRATION_SECONDS = 600;

    public boolean isReplay(String responseId) {
        if (responseId == null || responseId.isEmpty()) {
            return false;
        }

        Instant existing = processedResponseIds.putIfAbsent(responseId, Instant.now().plusSeconds(EXPIRATION_SECONDS));
        if (existing != null) {
            logger.warn("Replay attack detected for response ID: {}", responseId);
            return true;
        }

        return false;
    }

    @Scheduled(fixedRate = 300000) // Clean up every 5 minutes
    public void cleanupExpiredEntries() {
        Instant now = Instant.now();
        int removed = 0;

        var iterator = processedResponseIds.entrySet().iterator();
        while (iterator.hasNext()) {
            var entry = iterator.next();
            if (entry.getValue().isBefore(now)) {
                iterator.remove();
                removed++;
            }
        }

        if (removed > 0) {
            logger.debug("Cleaned up {} expired response IDs", removed);
        }
    }
}

